import random
from typing import List

class Article:
    def __init__(self, title: str, author: str, content: str):
        self.title = title
        self.author = author
        self.content = content

    def __str__(self) -> str:
        return f"{self.title} by {self.author}:\n{self.content}"

def get_article() -> Article:
    title = input("Enter the title of the article: ")
    author = input("Enter the name of the author: ")
    content = input("Enter the content of the article: ")
    return Article(title, author, content)

def write_article(article: Article):
    print(article)

def main():
    article = get_article()
    write_article(article)

if __name__ == "__main__":
    main()
